<?php
namespace App\Models;
use Illuminate\Database\Eloquent\Factories\HasFactory; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\BelongsTo; use Illuminate\Database\Eloquent\Relations\BelongsToMany; use Illuminate\Database\Eloquent\Relations\HasMany;
class Business extends Model { use HasFactory; protected $fillable=['owner_id','name','legal_name','email','phone','currency','vat_rate','address','city','state','country','tax_id']; protected function casts(): array { return ['vat_rate'=>'decimal:2']; } public function owner(): BelongsTo { return $this->belongsTo(User::class,'owner_id'); } public function users(): BelongsToMany { return $this->belongsToMany(User::class)->withPivot('role')->withTimestamps(); } public function customers(): HasMany { return $this->hasMany(Customer::class); } public function vendors(): HasMany { return $this->hasMany(Vendor::class); } public function products(): HasMany { return $this->hasMany(Product::class); } public function bankAccounts(): HasMany { return $this->hasMany(BankAccount::class); } public function invoices(): HasMany { return $this->hasMany(Invoice::class); } public function expenses(): HasMany { return $this->hasMany(Expense::class); } }
